255 bool llvm::isOnlyUsedInZeroComparison(const Instruction *I) {
256   return !I->user_empty() && all_of(I->users(), [](const User *U) {
257     ICmpInst::Predicate P;
258     return match(U, m_ICmp(P, m_Value(), m_Zero()));
259   });
