2118 /// Return true if the given value is known to have exactly one
2119 /// bit set when defined. For vectors return true if every element is known to
2120 /// be a power of two when defined. Supports values with integer or pointer
2121 /// types and vectors of integers.
2122 bool isKnownToBeAPowerOfTwo(const Value *V, bool OrZero, unsigned Depth,
2123                             const SimplifyQuery &Q) {
2124   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
2125 
2126   if (isa<Constant>(V))
2127     return OrZero ? match(V, m_Power2OrZero()) : match(V, m_Power2());
2128 
2129   // i1 is by definition a power of 2 or zero.
2130   if (OrZero && V->getType()->getScalarSizeInBits() == 1)
2131     return true;
2132 
2133   auto *I = dyn_cast<Instruction>(V);
2134   if (!I)
2135     return false;
2136 
2137   if (Q.CxtI && match(V, m_VScale())) {
2138     const Function *F = Q.CxtI->getFunction();
2139     // The vscale_range indicates vscale is a power-of-two.
2140     return F->hasFnAttribute(Attribute::VScaleRange);
2141   }
2142 
2143   // 1 << X is clearly a power of two if the one is not shifted off the end.  If
2144   // it is shifted off the end then the result is undefined.
2145   if (match(I, m_Shl(m_One(), m_Value())))
2146     return true;
2147 
2148   // (signmask) >>l X is clearly a power of two if the one is not shifted off
2149   // the bottom.  If it is shifted off the bottom then the result is undefined.
2150   if (match(I, m_LShr(m_SignMask(), m_Value())))
2151     return true;
2152 
2153   // The remaining tests are all recursive, so bail out if we hit the limit.
2154   if (Depth++ == MaxAnalysisRecursionDepth)
2155     return false;
2156 
2157   switch (I->getOpcode()) {
2158   case Instruction::ZExt:
2159     return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2160   case Instruction::Trunc:
2161     return OrZero && isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2162   case Instruction::Shl:
2163     if (OrZero || Q.IIQ.hasNoUnsignedWrap(I) || Q.IIQ.hasNoSignedWrap(I))
2164       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2165     return false;
2166   case Instruction::LShr:
2167     if (OrZero || Q.IIQ.isExact(cast<BinaryOperator>(I)))
2168       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2169     return false;
2170   case Instruction::UDiv:
2171     if (Q.IIQ.isExact(cast<BinaryOperator>(I)))
2172       return isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q);
2173     return false;
2174   case Instruction::Mul:
2175     return isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q) &&
2176            isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q) &&
2177            (OrZero || isKnownNonZero(I, Q, Depth));
2178   case Instruction::And:
2179     // A power of two and'd with anything is a power of two or zero.
2180     if (OrZero &&
2181         (isKnownToBeAPowerOfTwo(I->getOperand(1), /*OrZero*/ true, Depth, Q) ||
2182          isKnownToBeAPowerOfTwo(I->getOperand(0), /*OrZero*/ true, Depth, Q)))
2183       return true;
2184     // X & (-X) is always a power of two or zero.
2185     if (match(I->getOperand(0), m_Neg(m_Specific(I->getOperand(1)))) ||
2186         match(I->getOperand(1), m_Neg(m_Specific(I->getOperand(0)))))
2187       return OrZero || isKnownNonZero(I->getOperand(0), Q, Depth);
2188     return false;
2189   case Instruction::Add: {
2190     // Adding a power-of-two or zero to the same power-of-two or zero yields
2191     // either the original power-of-two, a larger power-of-two or zero.
2192     const OverflowingBinaryOperator *VOBO = cast<OverflowingBinaryOperator>(V);
2193     if (OrZero || Q.IIQ.hasNoUnsignedWrap(VOBO) ||
2194         Q.IIQ.hasNoSignedWrap(VOBO)) {
2195       if (match(I->getOperand(0),
2196                 m_c_And(m_Specific(I->getOperand(1)), m_Value())) &&
2197           isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q))
2198         return true;
2199       if (match(I->getOperand(1),
2200                 m_c_And(m_Specific(I->getOperand(0)), m_Value())) &&
2201           isKnownToBeAPowerOfTwo(I->getOperand(0), OrZero, Depth, Q))
2202         return true;
2203 
2204       unsigned BitWidth = V->getType()->getScalarSizeInBits();
2205       KnownBits LHSBits(BitWidth);
2206       computeKnownBits(I->getOperand(0), LHSBits, Depth, Q);
2207 
2208       KnownBits RHSBits(BitWidth);
2209       computeKnownBits(I->getOperand(1), RHSBits, Depth, Q);
2210       // If i8 V is a power of two or zero:
2211       //  ZeroBits: 1 1 1 0 1 1 1 1
2212       // ~ZeroBits: 0 0 0 1 0 0 0 0
2213       if ((~(LHSBits.Zero & RHSBits.Zero)).isPowerOf2())
2214         // If OrZero isn't set, we cannot give back a zero result.
2215         // Make sure either the LHS or RHS has a bit set.
2216         if (OrZero || RHSBits.One.getBoolValue() || LHSBits.One.getBoolValue())
2217           return true;
2218     }
2219 
2220     // LShr(UINT_MAX, Y) + 1 is a power of two (if add is nuw) or zero.
2221     if (OrZero || Q.IIQ.hasNoUnsignedWrap(VOBO))
2222       if (match(I, m_Add(m_LShr(m_AllOnes(), m_Value()), m_One())))
2223         return true;
2224     return false;
2225   }
2226   case Instruction::Select:
2227     return isKnownToBeAPowerOfTwo(I->getOperand(1), OrZero, Depth, Q) &&
2228            isKnownToBeAPowerOfTwo(I->getOperand(2), OrZero, Depth, Q);
2229   case Instruction::PHI: {
2230     // A PHI node is power of two if all incoming values are power of two, or if
2231     // it is an induction variable where in each step its value is a power of
2232     // two.
2233     auto *PN = cast<PHINode>(I);
2234     SimplifyQuery RecQ = Q;
2235 
2236     // Check if it is an induction variable and always power of two.
2237     if (isPowerOfTwoRecurrence(PN, OrZero, Depth, RecQ))
2238       return true;
2239 
2240     // Recursively check all incoming values. Limit recursion to 2 levels, so
2241     // that search complexity is limited to number of operands^2.
2242     unsigned NewDepth = std::max(Depth, MaxAnalysisRecursionDepth - 1);
2243     return llvm::all_of(PN->operands(), [&](const Use &U) {
2244       // Value is power of 2 if it is coming from PHI node itself by induction.
2245       if (U.get() == PN)
2246         return true;
2247 
2248       // Change the context instruction to the incoming block where it is
2249       // evaluated.
2250       RecQ.CxtI = PN->getIncomingBlock(U)->getTerminator();
2251       return isKnownToBeAPowerOfTwo(U.get(), OrZero, NewDepth, RecQ);
2252     });
2253   }
2254   case Instruction::Invoke:
2255   case Instruction::Call: {
2256     if (auto *II = dyn_cast<IntrinsicInst>(I)) {
2257       switch (II->getIntrinsicID()) {
2258       case Intrinsic::umax:
2259       case Intrinsic::smax:
2260       case Intrinsic::umin:
2261       case Intrinsic::smin:
2262         return isKnownToBeAPowerOfTwo(II->getArgOperand(1), OrZero, Depth, Q) &&
2263                isKnownToBeAPowerOfTwo(II->getArgOperand(0), OrZero, Depth, Q);
2264       // bswap/bitreverse just move around bits, but don't change any 1s/0s
2265       // thus dont change pow2/non-pow2 status.
2266       case Intrinsic::bitreverse:
2267       case Intrinsic::bswap:
2268         return isKnownToBeAPowerOfTwo(II->getArgOperand(0), OrZero, Depth, Q);
2269       case Intrinsic::fshr:
2270       case Intrinsic::fshl:
2271         // If Op0 == Op1, this is a rotate. is_pow2(rotate(x, y)) == is_pow2(x)
2272         if (II->getArgOperand(0) == II->getArgOperand(1))
2273           return isKnownToBeAPowerOfTwo(II->getArgOperand(0), OrZero, Depth, Q);
2274         break;
2275       default:
2276         break;
2277       }
2278     }
2279     return false;
2280   }
2281   default:
2282     return false;
2283   }
2284 }
